std::string processCommandLine(const std::string& inputCommand, ConfigurationFile& config) {
    std::istringstream iss(inputCommand);
    std::string action, result;

    if (!(iss >> action)) {
        return "Error: Empty command";
    }

    if (action == "set") {
        std::string key, value;
        if (iss >> key >> value) {
            config.setValue(key, value);
            return "Successfully set " + key + " to " + value;
        }
        return "Error: Invalid set command format";
    } 
    else if (action == "display") {
        std::string key;
        if (iss >> key) {
            std::string value = config.displaySetting(key);
            return key + " = " + value;
        } else {
            std::string allSettings = config.displayAllSettings();
            return allSettings;
        }
        return true;
    } 
    else if (action == "reset") {
        std::string key;
        if (iss >> key) {
            config.resetSetting(key);
            return "Reset " + key + " to default value";
        } else {
            config.resetAllSettings();
            return "All settings reset to defaults";
        }
    }

    return "Error: Unknown command '" + action + "'";
}

