fn process_image_data(data: (Vec<u8>, String)) -> Result<(Vec<u8>, String), Box<dyn std::error::Error>> {
    use image::{ImageFormat, DynamicImage};

    // Extract data and format from tuple
    let (bytes, format) = data;

    // Determine image format
    let img_format = match format.to_lowercase().as_str() {
        "jpg" | "jpeg" => ImageFormat::Jpeg,
        "png" => ImageFormat::Png,
        "gif" => ImageFormat::Gif,
        "webp" => ImageFormat::WebP,
        "tiff" => ImageFormat::Tiff,
        "bmp" => ImageFormat::Bmp,
        format_str => return Err(format!("Unsupported format: {}", format_str).into()),
    };

    // Decode the image from bytes
    let img = image::load_from_memory_with_format(&bytes, img_format)?;

    // Convert to grayscale
    let gray_img = img.grayscale();

    // Re-encode the image to the same format
    let mut output = Vec::new();
    let mut cursor = std::io::Cursor::new(&mut output);
    gray_img.write_to(&mut cursor, img_format)?;

    Ok((output, format))
}

